  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

const STEP_COUNT = 4;

function validateEmail(email: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = formData.features.length > 0;

  const canGoNext = useMemo(() => {
    if (step === 1) return isStep1Valid;
    if (step === 2) return isStep2Valid;
    if (step === 3) return isStep3Valid;
    return true;
  }, [step, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleNext = () => setStep((s) => Math.min(s + 1, STEP_COUNT + 1));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const renderStepContent = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Step 1: Contact Information</Heading>
            <Input
              label="Name"
              value={formData.name}
              onChange={(name) => setFormData((d) => ({ ...d, name }))}
              required
            />
            <Input
              label="Email"
              type="email"
              value={formData.email}
              onChange={(email) => setFormData((d) => ({ ...d, email }))}
              error={formData.email !== '' && !validateEmail(formData.email) ? 'Invalid email format' : undefined}
              required
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Step 2: Satisfaction</Heading>
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(val) => setFormData((d) => ({ ...d, satisfaction: parseInt(val) }))}
              options={[1, 2, 3, 4, 5].map((v) => ({
                value: v.toString(),
                label: `${v} - ${props.satisfactionLabels[v - 1] || ''}`,
              }))}
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Step 3: Interests</Heading>
            <Text>Which features are you interested in?</Text>
            {props.featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={formData.features.includes(feature)}
                onChange={(checked) =>
                  setFormData((d) => ({
                    ...d,
                    features: checked ? [...d.features, feature] : d.features.filter((f) => f !== feature),
                  }))
                }
              />
            ))}
          </Stack>
        );
      case 4:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Step 4: Comments</Heading>
            <TextArea
              label="Open-ended comments"
              value={formData.comments}
              onChange={(comments) => setFormData((d) => ({ ...d, comments }))}
              maxLength={500}
              showCount
            />
          </Stack>
        );
      case 5:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Review</Heading>
            <Text>Name: {formData.name}</Text>
            <Text>Email: {formData.email}</Text>
            <Text>Satisfaction: {formData.satisfaction}</Text>
            <Text>Features: {formData.features.join(', ')}</Text>
            <Text>Comments: {formData.comments}</Text>
            <Button variant="primary" onClick={() => submit(formData)}>Submit Survey</Button>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Survey</Heading>
          {step <= STEP_COUNT && <Text>Step {step} of {STEP_COUNT}</Text>}
          {step <= STEP_COUNT && <Progress value={((step - 1) / STEP_COUNT) * 100} />}
        </Stack>
        <Card padding="var(--ggui-spacing-6)">
          {renderStepContent()}
        </Card>
        {step <= STEP_COUNT && (
          <Row gap="var(--ggui-spacing-4)">
            {step > 1 && <Button variant="secondary" onClick={handleBack}>Back</Button>}
            {step <= STEP_COUNT && (
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={!canGoNext}
              >
                {step === STEP_COUNT ? 'Review' : 'Next'}
              </Button>
            )}
          </Row>
        )}
      </Stack>
    </Container>
  );
}

