// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const MessageItem = ({ sender, text, timestamp, isOwn }: { sender: string; text: string; timestamp: string; isOwn: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    {!isOwn && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{sender}</Text>}
    <Box 
      padding="var(--ggui-spacing-3)" 
      borderRadius="var(--ggui-shape-radius-lg)" 
      background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
    >
      <Text color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{text}</Text>
    </Box>
    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
      {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
    </Text>
  </Stack>
);

export default function Component(props: Props) {
  const [messages, setMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const messageStream = useStream<StreamMessage>('message');
  const typingStream = useStream<StreamTyping>('typing');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messageStream.latest) {
      setMessages((prev) => [...prev, messageStream.latest!]);
    }
  }, [messageStream.latest]);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    const msg = { text: inputText, timestamp: new Date().toISOString() };
    sendMessage(msg);
    setMessages((prev) => [...prev, { sender: props.currentUser, ...msg }]);
    setInputText('');
  };

  const typingUsers = useMemo(() => 
    typingStream.all
      .filter(t => t.active)
      .map(t => t.sender)
      .filter((v, i, a) => a.indexOf(v) === i), 
  [typingStream.all]);

  return (
    <Container maxWidth="md" padding="0" center={false}>
      <Card padding="0" shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '80vh' }}>
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
          <Row align="center" gap="var(--ggui-spacing-2)">
            <Heading level={3}>{props.title}</Heading>
            <Badge variant="default">{props.participantCount} online</Badge>
          </Row>
          {typingUsers.length > 0 && (
            <Text variant="caption" color="var(--ggui-color-primary-600)">{typingUsers.join(', ')} typing...</Text>
          )}
        </Box>
        <Box ref={scrollRef} padding="var(--ggui-spacing-4)" style={{ flex: 1, overflowY: 'auto' }}>
          <Stack gap="var(--ggui-spacing-4)">
            {messages.map((m, i) => (
              <MessageItem 
                key={i} 
                sender={m.sender || 'Unknown'} 
                text={m.text || ''} 
                timestamp={m.timestamp || new Date().toISOString()}
                isOwn={m.sender === props.currentUser}
              />
            ))}
          </Stack>
        </Box>
        <Divider margin={0} />
        <Row padding="var(--ggui-spacing-4)" gap="var(--ggui-spacing-2)" align="end">
          <Box style={{ flex: 1 }}>
            <Input 
              label="Compose message" 
              value={inputText} 
              onChange={setInputText} 
              onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
            />
          </Box>
          <Button disabled={!inputText.trim()} onClick={handleSend}>Send</Button>
        </Row>
      </Card>
    </Container>
  );
}

