import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const StepIndicator = (props: { current: number; total: number }) => (
  <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
    <Text variant="label" color="var(--ggui-color-primary-600)">Step {props.current} / {props.total}</Text>
    <Box flex={1} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-full)" height="8px" overflow="hidden">
      <Box background="var(--ggui-color-primary-600)" height="100%" style={{ width: `${(props.current / props.total) * 100}%` }} />
    </Box>
  </Stack>
);

export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile?.role || props.roleOptions[0] || '',
    emailNotifications: !!props.initialProfile?.emailNotifications,
    theme: props.initialProfile?.theme || 'light'
  });

  const complete = useAction<ActionCompletePayload>('complete');

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && isValidEmail(formData.email);

  const next = () => setStep(s => Math.min(s + 1, 3));
  const back = () => setStep(s => Math.max(s - 1, 1));

  const submit = () => complete(formData as ActionCompletePayload);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <StepIndicator current={step} total={3} />

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-6)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Profile Setup</Heading>
                <Input label="Name" value={formData.name} onChange={(v) => setFormData(f => ({ ...f, name: v }))} required />
                <Input label="Email" value={formData.email} onChange={(v) => setFormData(f => ({ ...f, email: v }))} required error={formData.email && !isValidEmail(formData.email) ? 'Invalid email format' : ''} />
                <Text variant="label">Choose Avatar</Text>
                <Row gap="var(--ggui-spacing-2)">
                  {props.avatarOptions.map(emoji => (
                    <Box key={emoji} as={Clickable} onClick={() => setFormData(f => ({ ...f, avatar: emoji }))} padding="var(--ggui-spacing-2)" background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'transparent'} borderRadius="var(--ggui-shape-radius-md)">
                      <Text size="2xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Preferences</Heading>
                <Select label="Role" value={formData.role} onChange={(v) => setFormData(f => ({ ...f, role: v }))} options={props.roleOptions.map(r => ({ value: r, label: r }))} />
                <Row justify="between" align="center">
                  <Text variant="body">Enable Email Notifications</Text>
                  <Toggle checked={formData.emailNotifications} onChange={(v) => setFormData(f => ({ ...f, emailNotifications: v }))} label="" />
                </Row>
                <Row justify="between" align="center">
                  <Text variant="body">Dark Mode</Text>
                  <Toggle checked={formData.theme === 'dark'} onChange={(v) => setFormData(f => ({ ...f, theme: v ? 'dark' : 'light' }))} label="" />
                </Row>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Review</Heading>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Name: {formData.name}</Text>
                  <Text variant="label">Email: {formData.email}</Text>
                  <Text variant="label">Role: {formData.role}</Text>
                  <Text variant="label">Avatar: {formData.avatar}</Text>
                </Stack>
              </Stack>
            )}

            <Row gap="var(--ggui-spacing-4)" justify="between">
              <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
              {step < 3 ? (
                <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
              ) : (
                <Button variant="primary" onClick={submit}>Complete Setup</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
